import {
  isFilterFieldKeySuggestionConfig,
  isFilterFieldKeySuggestionGroupConfig,
  isFilterFieldRichValuePredicate,
  isFilterFieldValidatorMapDurationSpecification,
  isFilterFieldValidatorMapTypeSpecification,
  isFilterFieldValueSuggestionGroupConfig,
} from './type-guards.js';
import type {
  FallbackKeys,
  FilterStatementFunctionMap,
  FilterStatementKeysMap,
  FilterStatementValuesMap,
} from '../../FilterField.types.js';
import type {
  FilterFieldComparisonOperators,
  FilterFieldKeySuggestionConfig,
  FilterFieldKeySuggestionGroupConfig,
  FilterFieldValidatorMap,
  FilterFieldValueMatchFn,
  FilterFieldValuePredicate,
  FilterFieldValuePredicateFn,
  FilterFieldValuePredicateItem,
} from '../../types/validation.js';
import { resolveGroupId } from '../suggestions-utils/suggestion-group-utils.js';

/**
 * Normalized per-key configuration for use in the internal validation and suggestion pipeline.
 * @internal
 */
export type NormalizedKeyConfig = {
  comparisonOperators?: Array<FilterFieldComparisonOperators>;
  valuePredicate?: FilterFieldValuePredicate | FilterFieldValuePredicateFn;
  /** Value type from the new array format's `valueType` prop. Stored separately from `valuePredicate`
   * to avoid fabricating a synthetic type predicate object. */
  valueType?: string | string[];
  fallbackKey?:
    | boolean
    | Array<Exclude<FilterFieldComparisonOperators, 'exists' | 'not-exists'>>;
  suggestStatementOnValueMatch?: boolean | FilterFieldValueMatchFn;
  /** Display value shown for key suggestions (from deprecated object format). */
  displayValue?: string;
  /** Detail text shown for key suggestions (from deprecated object format). */
  details?: string;
};

/**
 * A named key group for suggestion rendering.
 * @internal
 */
export type KeyGroup = {
  id: string;
  label?: string;
  'aria-label'?: string;
  keys: string[];
};

/**
 * Normalized key predicates for the internal validation and suggestion pipeline.
 * @internal
 */
export type NormalizedKeyPredicates = {
  /** Flat per-key configuration map for validation and operator/value lookup. */
  byKey: Map<string, NormalizedKeyConfig>;
  /** Ordered named groups for suggestion rendering (undefined = no named groups). */
  groups?: KeyGroup[];
  /** Pre-computed key → group mapping for lookup during suggestion rendering. */
  keyToGroup: Map<string, KeyGroup>;
};

/**
 * Internal representation of the FilterField validator map.
 * Replaces `FilterFieldValidatorMap` in the suggestion and validation pipeline.
 * The raw `keyPredicates` are not exposed — use `normalizedKeys` instead.
 * @internal
 */
export type InternalValidatorMap = {
  /** Normalized per-key configs keyed by key string. */
  normalizedKeys: NormalizedKeyPredicates;
  /** Whether any key not in `normalizedKeys.byKey` is considered an error. */
  exhaustive?: boolean;
  /** Global comparison operator restrictions. */
  comparisonOperators?: Array<FilterFieldComparisonOperators>;
  /** Whether suggestions should be sorted alphabetically by default. Defaults to true. */
  sortSuggestions?: boolean;
  /** Pre-computed fallback keys for suggestion generation. */
  fallbackKeys?: FallbackKeys;
  /** Pre-computed filter statement keys map for statement suggestions. */
  filterStatementKeysMap?: FilterStatementKeysMap;
};

/**
 * The well-known group id for the primary (ungrouped) key suggestion slot.
 * Individual key entries in the array format and all object-format keys are assigned
 * to this id so they map to `groupedSuggestions.key` in the suggestion pipeline.
 * @internal
 */
export const KEY_GROUP_ID = 'strato-filter-field-key-suggestions';

/**
 * Normalizes a `FilterFieldValidatorMap` into an `InternalValidatorMap`.
 * Handles all formats of `keyPredicates` (deprecated object, new array).
 * Computes `fallbackKeys` and `filterStatementKeysMap` in the same pass.
 * @internal
 */
export function toInternalValidatorMap(
  validatorMap: FilterFieldValidatorMap | undefined,
): InternalValidatorMap | undefined {
  if (!validatorMap) {
    return undefined;
  }
  const byKey = new Map<string, NormalizedKeyConfig>();
  const valuesMap: FilterStatementValuesMap = new Map<string, string[]>();
  const functionsMap: FilterStatementFunctionMap = new Map<
    string,
    FilterFieldValueMatchFn
  >();
  const fallbackKeysList: FallbackKeys = [];
  let groups: KeyGroup[] | undefined;

  const { keyPredicates, exhaustive, comparisonOperators } = validatorMap;

  if (keyPredicates !== undefined) {
    if (Array.isArray(keyPredicates)) {
      groups = processKeyPredicatesArray(
        keyPredicates,
        byKey,
        valuesMap,
        functionsMap,
        fallbackKeysList,
      );
    } else {
      processKeyPredicatesObject(
        keyPredicates,
        byKey,
        valuesMap,
        functionsMap,
        fallbackKeysList,
      );
    }
  }

  const filterStatementKeysMap: FilterStatementKeysMap | undefined =
    valuesMap.size > 0 || functionsMap.size > 0
      ? { values: valuesMap, functions: functionsMap }
      : undefined;

  const resolvedGroups = groups && groups.length > 0 ? groups : undefined;
  const keyToGroup = new Map<string, KeyGroup>();

  if (resolvedGroups) {
    for (const group of resolvedGroups) {
      for (const key of group.keys) {
        keyToGroup.set(key, group);
      }
    }
  } else {
    // Object format: all keys fall into a single implicit group.
    const implicitGroup: KeyGroup = {
      id: `${KEY_GROUP_ID}-implicit-0`,
      keys: [...byKey.keys()],
    };
    for (const key of byKey.keys()) {
      keyToGroup.set(key, implicitGroup);
    }
  }

  return {
    normalizedKeys: {
      byKey,
      groups: resolvedGroups,
      keyToGroup,
    },
    exhaustive,
    comparisonOperators,
    sortSuggestions: validatorMap.sortSuggestions,
    fallbackKeys: fallbackKeysList.length > 0 ? fallbackKeysList : undefined,
    filterStatementKeysMap,
  };
}

/**
 * Processes the new array format for `keyPredicates`.
 * Returns all groups in declaration order, both explicit named groups and implicit
 * groups formed by consecutive individual key entries.
 * Individual keys are collected into an implicit group to preserve the correct order
 * of suggestions when groups and individual keys are combined.
 * E.g.:
 * ```
 * [
 *   'key1',
 *   { key: 'key2', ... },
 *   { label: 'Group A', suggestions: ['key3', { key: 'key4', ... }] },
 *   'key5',
 * ]
 * ```
 * Result groups:
 * ```
 * { id: 'key-group-0', keys: ['key1', 'key2'] }
 * { id: 'group-a', label: 'Group A', keys: ['key3', 'key4'] }
 * { id: 'key-group-1', keys: ['key5'] }
 * ```
 */
function processKeyPredicatesArray(
  keyPredicates: Array<
    | string
    | FilterFieldKeySuggestionConfig
    | FilterFieldKeySuggestionGroupConfig
  >,
  byKey: Map<string, NormalizedKeyConfig>,
  valuesMap: FilterStatementValuesMap,
  functionsMap: FilterStatementFunctionMap,
  fallbackKeysList: FallbackKeys,
): KeyGroup[] {
  const groups: KeyGroup[] = [];
  // Collect consecutive individual keys to be added as an implicit group.
  let pendingKeys: string[] = [];

  /**
   * Push accumulated individual items into an implicit group.
   * Individual keys are collected into an implicit group to preserve the correct
   * declaration order when mixing groups and individual keys in the key predicates.
   */
  function processPendingKeys() {
    if (pendingKeys.length === 0) {
      return;
    }

    groups.push({
      id: `${KEY_GROUP_ID}-implicit-${groups.length}`,
      keys: pendingKeys,
    });
    pendingKeys = [];
  }

  for (let index = 0; index < keyPredicates.length; index++) {
    const item = keyPredicates[index];

    // Plain string key — no per-key restrictions.
    if (typeof item === 'string') {
      byKey.set(item, {});
      pendingKeys.push(item);
      continue;
    }

    // Individual key suggestion config.
    if (isFilterFieldKeySuggestionConfig(item)) {
      byKey.set(item.key, item);
      collectFallbackAndStatements(
        item.key,
        item,
        fallbackKeysList,
        valuesMap,
        functionsMap,
      );
      pendingKeys.push(item.key);
      continue;
    }

    // Explicit group config.
    if (isFilterFieldKeySuggestionGroupConfig(item)) {
      // Pending keys are first pushed as an implicit group to preserve declaration order relative to the explicit group.
      processPendingKeys();

      const { label, 'aria-label': ariaLabel } = item;
      const groupId = resolveGroupId(item, `key-group-${index}`);
      const groupKeys: string[] = [];

      for (const suggestion of item.suggestions) {
        if (typeof suggestion === 'string') {
          byKey.set(suggestion, {});
          groupKeys.push(suggestion);
        } else if (isFilterFieldKeySuggestionConfig(suggestion)) {
          byKey.set(suggestion.key, suggestion);
          groupKeys.push(suggestion.key);
          collectFallbackAndStatements(
            suggestion.key,
            suggestion,
            fallbackKeysList,
            valuesMap,
            functionsMap,
          );
        }
      }

      if (groupKeys.length > 0) {
        groups.push({
          id: groupId,
          label,
          'aria-label': ariaLabel,
          keys: groupKeys,
        });
      }
    }
  }

  // Push any remaining individual keys at the end as an implicit group.
  processPendingKeys();

  return groups;
}

/**
 * Processes the deprecated object format for `keyPredicates`.
 */
function processKeyPredicatesObject(
  keyPredicates: Extract<
    NonNullable<FilterFieldValidatorMap['keyPredicates']>,
    Record<string, unknown>
  >,
  byKey: Map<string, NormalizedKeyConfig>,
  valuesMap: FilterStatementValuesMap,
  functionsMap: FilterStatementFunctionMap,
  fallbackKeysList: FallbackKeys,
): void {
  for (const [key, rawPredicate] of Object.entries(keyPredicates)) {
    let config: NormalizedKeyConfig;

    if (isFilterFieldValidatorMapTypeSpecification(rawPredicate)) {
      config = { valuePredicate: rawPredicate };
    } else {
      config = {
        comparisonOperators: rawPredicate.comparisonOperators,
        valuePredicate: rawPredicate.valuePredicate,
        fallbackKey: rawPredicate.fallbackKey,
        suggestStatementOnValueMatch: rawPredicate.suggestStatementOnValueMatch,
        displayValue: rawPredicate.displayValue,
        details: rawPredicate.details,
      };
    }

    byKey.set(key, config);
    collectFallbackAndStatements(
      key,
      config,
      fallbackKeysList,
      valuesMap,
      functionsMap,
    );
  }
}

/**
 * Collects fallback key info and statement suggestion mappings from a normalized config.
 */
function collectFallbackAndStatements(
  key: string,
  config: NormalizedKeyConfig,
  fallbackKeysList: FallbackKeys,
  valuesMap: FilterStatementValuesMap,
  functionsMap: FilterStatementFunctionMap,
): void {
  if (config.fallbackKey) {
    fallbackKeysList.push({
      value: key,
      comparisonOperators: Array.isArray(config.fallbackKey)
        ? config.fallbackKey
        : undefined,
    });
  }

  if (config.suggestStatementOnValueMatch) {
    if (typeof config.suggestStatementOnValueMatch === 'function') {
      functionsMap.set(key, config.suggestStatementOnValueMatch);
    } else if (
      config.valuePredicate !== undefined &&
      typeof config.valuePredicate !== 'function'
    ) {
      extractLiteralValuesToMap(config.valuePredicate, key, valuesMap);
    }
  }
}

/**
 * Extracts literal value strings from a `FilterFieldValuePredicate` into the
 * `valuesMap` for statement suggestion lookup.
 * Handles grouped value configs by recursing into their `suggestions` arrays.
 */
function extractLiteralValuesToMap(
  valuePredicate: Exclude<
    FilterFieldValuePredicate,
    FilterFieldValuePredicateFn
  >,
  key: string,
  valuesMap: FilterStatementValuesMap,
): void {
  if (Array.isArray(valuePredicate)) {
    for (const item of valuePredicate) {
      if (isFilterFieldValueSuggestionGroupConfig(item)) {
        for (const suggestion of item.suggestions) {
          if (!isFilterFieldValidatorMapTypeSpecification(suggestion)) {
            addToValuesMap(valuesMap, key, suggestion);
          }
        }
      } else if (!isFilterFieldValidatorMapTypeSpecification(item)) {
        addToValuesMap(valuesMap, key, item);
      }
    }
  } else if (isFilterFieldValueSuggestionGroupConfig(valuePredicate)) {
    for (const suggestion of valuePredicate.suggestions) {
      if (!isFilterFieldValidatorMapTypeSpecification(suggestion)) {
        addToValuesMap(valuesMap, key, suggestion);
      }
    }
  } else if (!isFilterFieldValidatorMapTypeSpecification(valuePredicate)) {
    addToValuesMap(valuesMap, key, valuePredicate);
  }
}

/**
 * Adds a key → value string mapping to the values map.
 * Inlined from `getValuePredicateTextValue` to avoid circular imports.
 */
function addToValuesMap(
  valuesMap: FilterStatementValuesMap,
  key: string,
  value: FilterFieldValuePredicateItem,
): void {
  let stringValue: string;
  if (isFilterFieldValidatorMapDurationSpecification(value)) {
    stringValue = `${value.value}${value.unit}`;
  } else if (isFilterFieldRichValuePredicate(value)) {
    stringValue = `${value.value}`;
  } else {
    stringValue = `${value}`;
  }
  const existingKeys = valuesMap.get(stringValue) ?? [];
  if (!existingKeys.includes(key)) {
    valuesMap.set(stringValue, [...existingKeys, key]);
  }
}
